# solution.py
"""TeamCollaborationManager system.

Standard library only, ASCII only. Implemented to satisfy the bundled
test_solution.py contract (155 tests).
"""

import csv
import io
import threading
from dataclasses import dataclass, field, replace
from datetime import datetime
from enum import Enum
from typing import List, Optional


# ---------------------------------------------------------------------------
# Enums
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(Enum):
    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    TEAM_PERFORMANCE = "team_performance"
    PROJECT_PROGRESS = "project_progress"
    INDIVIDUAL = "individual"


# ---------------------------------------------------------------------------
# Exceptions
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base exception for the collaboration system."""


class ValidationError(TeamCollaborationError):
    pass


class NotFoundError(TeamCollaborationError):
    pass


class AuthorizationError(TeamCollaborationError):
    pass


class DuplicateError(TeamCollaborationError):
    pass


class ConflictError(TeamCollaborationError):
    pass


# ---------------------------------------------------------------------------
# Data classes (non-frozen; callers mutate returned copies)
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    owner_id: int
    start_date: datetime
    end_date: datetime
    description: str = ""


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int] = None
    deadline: Optional[datetime] = None
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Lightweight store-isolation clone
# ---------------------------------------------------------------------------
# Every stored dataclass holds only immutable scalar fields (int, str, Enum,
# datetime) except Message.attachments, which is a list of (also immutable)
# Attachment records. A flat dataclasses.replace() therefore yields a fully
# isolated copy for every type; Message additionally gets a fresh attachments
# list of cloned Attachments so mutating the returned list or any attachment
# never touches the store. This avoids copy.deepcopy on every getter/list call.
def _clone(obj):
    if type(obj) is Message:
        return replace(obj, attachments=[replace(a) for a in obj.attachments])
    return replace(obj)


# ---------------------------------------------------------------------------
# Sub-components (share the manager's lock + back-reference)
# ---------------------------------------------------------------------------
class _UserRepo:
    def __init__(self, lock):
        self._lock = lock
        self.data = {}


class _ProjectRepo:
    def __init__(self, lock):
        self._lock = lock
        self.data = {}


class _TaskRepo:
    def __init__(self, lock):
        self._lock = lock
        self.data = {}
        self.by_assignee = {}


class _MessageRepo:
    def __init__(self, lock):
        self._lock = lock
        self.data = {}


class _PerformanceService:
    def __init__(self, lock, manager):
        self._lock = lock
        self._manager = manager
        self.ratings = {}


class _ReportService:
    def __init__(self, lock, manager):
        self._lock = lock
        self._manager = manager


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    def __init__(self, now=None):
        self._now = now if now is not None else datetime.now
        self._lock = threading.RLock()
        self._id_counter = 0

        self.users = _UserRepo(self._lock)
        self.projects = _ProjectRepo(self._lock)
        self.tasks = _TaskRepo(self._lock)
        self.messages = _MessageRepo(self._lock)
        self.performance = _PerformanceService(self._lock, self)
        self.reports = _ReportService(self._lock, self)

    # -- id helper (call under lock) --
    def _next_id(self):
        self._id_counter += 1
        return self._id_counter

    # ------------------------------------------------------------------
    # User management
    # ------------------------------------------------------------------
    def register_user(self, username, email, role=UserRole.MEMBER):
        with self._lock:
            self._validate_username(username)
            self._validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            for u in self.users.data.values():
                if u.username == username:
                    raise DuplicateError("username already exists")
                if u.email == email:
                    raise DuplicateError("email already exists")
            uid = self._next_id()
            user = User(
                id=uid,
                username=username,
                email=email,
                role=role,
                created_at=self._now(),
            )
            self.users.data[uid] = user
            return _clone(user)

    def get_user(self, user_id):
        with self._lock:
            user = self.users.data.get(user_id)
            if user is None:
                raise NotFoundError("user not found")
            return _clone(user)

    def list_users(self):
        with self._lock:
            return [
                _clone(self.users.data[k])
                for k in sorted(self.users.data)
            ]

    def update_user(self, user_id, username=None, email=None, role=None):
        with self._lock:
            user = self.users.data.get(user_id)
            if user is None:
                raise NotFoundError("user not found")
            if username is not None:
                self._validate_username(username)
            if email is not None:
                self._validate_email(email)
            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            if username is not None:
                for u in self.users.data.values():
                    if u.id != user_id and u.username == username:
                        raise DuplicateError("username already exists")
            if email is not None:
                for u in self.users.data.values():
                    if u.id != user_id and u.email == email:
                        raise DuplicateError("email already exists")
            if username is not None:
                user.username = username
            if email is not None:
                user.email = email
            if role is not None:
                user.role = role
            return _clone(user)

    def delete_user(self, user_id):
        with self._lock:
            if user_id not in self.users.data:
                raise NotFoundError("user not found")
            for p in self.projects.data.values():
                if p.owner_id == user_id:
                    raise ConflictError("user owns a project")
            for t in self.tasks.data.values():
                if t.assignee_id == user_id and t.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has an open task")
            del self.users.data[user_id]
            self.tasks.by_assignee.pop(user_id, None)

    # ------------------------------------------------------------------
    # Project management
    # ------------------------------------------------------------------
    def create_project(self, name, start_date, end_date, owner_id, description=""):
        with self._lock:
            if owner_id not in self.users.data:
                raise NotFoundError("owner not found")
            if not name or not str(name).strip():
                raise ValidationError("name required")
            if end_date < start_date:
                raise ValidationError("end_date before start_date")
            pid = self._next_id()
            project = Project(
                id=pid,
                name=name,
                owner_id=owner_id,
                start_date=start_date,
                end_date=end_date,
                description=description,
            )
            self.projects.data[pid] = project
            return _clone(project)

    def get_project(self, project_id):
        with self._lock:
            project = self.projects.data.get(project_id)
            if project is None:
                raise NotFoundError("project not found")
            return _clone(project)

    def list_projects(self):
        with self._lock:
            return [
                _clone(self.projects.data[k])
                for k in sorted(self.projects.data)
            ]

    def update_project(self, project_id, name=None, start_date=None,
                       end_date=None, description=None):
        with self._lock:
            project = self.projects.data.get(project_id)
            if project is None:
                raise NotFoundError("project not found")
            if name is not None and (not name or not str(name).strip()):
                raise ValidationError("name required")
            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date
            if new_end < new_start:
                raise ValidationError("end_date before start_date")
            if name is not None:
                project.name = name
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description
            return _clone(project)

    def delete_project(self, project_id):
        with self._lock:
            if project_id not in self.projects.data:
                raise NotFoundError("project not found")
            task_ids = [
                t.id for t in self.tasks.data.values()
                if t.project_id == project_id
            ]
            for tid in task_ids:
                task = self.tasks.data.pop(tid, None)
                if task is not None and task.assignee_id is not None:
                    self._remove_from_assignee_index(task.assignee_id, tid)
            msg_ids = [
                m.id for m in self.messages.data.values()
                if m.project_id == project_id
            ]
            for mid in msg_ids:
                self.messages.data.pop(mid, None)
            del self.projects.data[project_id]

    # ------------------------------------------------------------------
    # Task management
    # ------------------------------------------------------------------
    def create_task(self, project_id, title, assignee_id=None, deadline=None):
        with self._lock:
            project = self.projects.data.get(project_id)
            if project is None:
                raise NotFoundError("project not found")
            if assignee_id is not None and assignee_id not in self.users.data:
                raise NotFoundError("assignee not found")
            if not title or not str(title).strip():
                raise ValidationError("title required")
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline before project start")
            tid = self._next_id()
            task = Task(
                id=tid,
                project_id=project_id,
                title=title,
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
            )
            self.tasks.data[tid] = task
            if assignee_id is not None:
                self._add_to_assignee_index(assignee_id, tid)
            return _clone(task)

    def get_task(self, task_id):
        with self._lock:
            task = self.tasks.data.get(task_id)
            if task is None:
                raise NotFoundError("task not found")
            return _clone(task)

    def list_tasks_by_project(self, project_id):
        with self._lock:
            if project_id not in self.projects.data:
                raise NotFoundError("project not found")
            tasks = [
                t for t in self.tasks.data.values()
                if t.project_id == project_id
            ]
            tasks.sort(key=lambda t: t.id)
            return [_clone(t) for t in tasks]

    def list_tasks_by_assignee(self, user_id):
        with self._lock:
            if user_id not in self.users.data:
                raise NotFoundError("user not found")
            ids = sorted(self.tasks.by_assignee.get(user_id, set()))
            return [_clone(self.tasks.data[i]) for i in ids]

    def assign_task(self, task_id, assignee_id):
        with self._lock:
            task = self.tasks.data.get(task_id)
            if task is None:
                raise NotFoundError("task not found")
            if assignee_id not in self.users.data:
                raise NotFoundError("assignee not found")
            if task.assignee_id is not None:
                self._remove_from_assignee_index(task.assignee_id, task_id)
            task.assignee_id = assignee_id
            self._add_to_assignee_index(assignee_id, task_id)
            return _clone(task)

    def reassign_task(self, task_id, new_assignee_id):
        return self.assign_task(task_id, new_assignee_id)

    def unassign_task(self, task_id):
        with self._lock:
            task = self.tasks.data.get(task_id)
            if task is None:
                raise NotFoundError("task not found")
            if task.assignee_id is not None:
                self._remove_from_assignee_index(task.assignee_id, task_id)
            task.assignee_id = None
            return _clone(task)

    def set_deadline(self, task_id, deadline):
        with self._lock:
            task = self.tasks.data.get(task_id)
            if task is None:
                raise NotFoundError("task not found")
            if deadline is None:
                task.deadline = None
                return _clone(task)
            project = self.projects.data.get(task.project_id)
            if project is not None and deadline < project.start_date:
                raise ValidationError("deadline before project start")
            task.deadline = deadline
            return _clone(task)

    def update_status(self, task_id, status):
        with self._lock:
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")
            task = self.tasks.data.get(task_id)
            if task is None:
                raise NotFoundError("task not found")
            now = self._now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            elif status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            task.status = status
            return _clone(task)

    # ------------------------------------------------------------------
    # Messaging
    # ------------------------------------------------------------------
    def post_message(self, author_id, body, project_id=None, task_id=None,
                     parent_id=None, attachments=None):
        with self._lock:
            if project_id is None and task_id is None:
                raise ValidationError("a target is required")
            if project_id is not None and task_id is not None:
                raise ValidationError("only one target allowed")
            if author_id not in self.users.data:
                raise NotFoundError("author not found")
            if project_id is not None and project_id not in self.projects.data:
                raise NotFoundError("project not found")
            if task_id is not None and task_id not in self.tasks.data:
                raise NotFoundError("task not found")
            if parent_id is not None and parent_id not in self.messages.data:
                raise NotFoundError("parent not found")
            has_attachments = bool(attachments)
            if (body is None or not str(body).strip()) and not has_attachments:
                raise ValidationError("body or attachment required")
            now = self._now()
            att_list = []
            if attachments:
                for filename, data in attachments:
                    att_list.append(
                        Attachment(
                            filename=filename,
                            size=len(data),
                            uploaded_by=author_id,
                            uploaded_at=now,
                        )
                    )
            mid = self._next_id()
            message = Message(
                id=mid,
                author_id=author_id,
                body=body,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=att_list,
                created_at=now,
                edited_at=None,
            )
            self.messages.data[mid] = message
            return _clone(message)

    def edit_message(self, message_id, editor_id, new_body):
        with self._lock:
            message = self.messages.data.get(message_id)
            if message is None:
                raise NotFoundError("message not found")
            if message.author_id != editor_id:
                raise AuthorizationError("not the author")
            if new_body is None or not str(new_body).strip():
                raise ValidationError("body required")
            message.body = new_body
            message.edited_at = self._now()
            return _clone(message)

    def add_attachment(self, message_id, user_id, filename, data):
        with self._lock:
            message = self.messages.data.get(message_id)
            if message is None:
                raise NotFoundError("message not found")
            if message.author_id != user_id:
                raise AuthorizationError("not the author")
            if not filename or not str(filename).strip():
                raise ValidationError("filename required")
            message.attachments.append(
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=user_id,
                    uploaded_at=self._now(),
                )
            )
            return _clone(message)

    def list_messages_by_project(self, project_id):
        with self._lock:
            if project_id not in self.projects.data:
                raise NotFoundError("project not found")
            msgs = [
                m for m in self.messages.data.values()
                if m.project_id == project_id
            ]
            msgs.sort(key=lambda m: m.id)
            return [_clone(m) for m in msgs]

    def list_messages_by_task(self, task_id):
        with self._lock:
            if task_id not in self.tasks.data:
                raise NotFoundError("task not found")
            msgs = [
                m for m in self.messages.data.values()
                if m.task_id == task_id
            ]
            msgs.sort(key=lambda m: m.id)
            return [_clone(m) for m in msgs]

    def delete_message(self, message_id, user_id):
        with self._lock:
            message = self.messages.data.get(message_id)
            if message is None:
                raise NotFoundError("message not found")
            if message.author_id != user_id:
                raise AuthorizationError("not the author")
            del self.messages.data[message_id]

    # ------------------------------------------------------------------
    # Performance
    # ------------------------------------------------------------------
    def get_completion_rate(self, user_id):
        with self._lock:
            if user_id not in self.users.data:
                raise NotFoundError("user not found")
            tasks = self._assigned_tasks(user_id)
            if not tasks:
                return 0.0
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            return completed / len(tasks)

    def get_average_completion_time(self, user_id):
        with self._lock:
            if user_id not in self.users.data:
                raise NotFoundError("user not found")
            durations = []
            for t in self._assigned_tasks(user_id):
                if (t.status == TaskStatus.COMPLETED and t.started_at is not None
                        and t.completed_at is not None):
                    durations.append(
                        (t.completed_at - t.started_at).total_seconds()
                    )
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None):
        with self._lock:
            if rater_id not in self.users.data:
                raise NotFoundError("rater not found")
            if ratee_id not in self.users.data:
                raise NotFoundError("ratee not found")
            if rater_id == ratee_id:
                raise ConflictError("cannot rate self")
            if not isinstance(score, int) or score < 1 or score > 5:
                raise ValidationError("score must be 1..5")
            if task_id is not None and task_id not in self.tasks.data:
                raise NotFoundError("task not found")
            rid = self._next_id()
            rating = Rating(
                id=rid,
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback,
                task_id=task_id,
                created_at=self._now(),
            )
            self.performance.ratings[rid] = rating
            return _clone(rating)

    def get_ratings_summary(self, user_id):
        with self._lock:
            if user_id not in self.users.data:
                raise NotFoundError("user not found")
            ratings = [
                r for r in self.performance.ratings.values()
                if r.ratee_id == user_id
            ]
            ratings.sort(key=lambda r: r.id)
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / count if count else 0.0
            )
            return {
                "count": count,
                "average": average,
                "ratings": [_clone(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id):
        with self._lock:
            if user_id not in self.users.data:
                raise NotFoundError("user not found")
            tasks = self._assigned_tasks(user_id)
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            completion_rate = completed / total if total else 0.0
            avg_time = self.get_average_completion_time(user_id)
            summary = self.get_ratings_summary(user_id)
            return {
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": avg_time,
                "rating_count": summary["count"],
                "rating_average": summary["average"],
            }

    # ------------------------------------------------------------------
    # Reports
    # ------------------------------------------------------------------
    def project_progress_report(self, project_id):
        with self._lock:
            if project_id not in self.projects.data:
                raise NotFoundError("project not found")
            tasks = [
                t for t in self.tasks.data.values()
                if t.project_id == project_id
            ]
            total = len(tasks)
            status_counts = {s.value: 0 for s in TaskStatus}
            for t in tasks:
                status_counts[t.status.value] += 1
            completed = status_counts[TaskStatus.COMPLETED.value]
            completion_rate = completed / total if total else 0.0
            now = self._now()
            overdue = sum(
                1 for t in tasks
                if t.deadline is not None and t.deadline < now
                and t.status != TaskStatus.COMPLETED
            )
            per_assignee = {}
            for t in tasks:
                if t.assignee_id is None:
                    continue
                entry = per_assignee.setdefault(
                    t.assignee_id, {"total": 0, "completed": 0}
                )
                entry["total"] += 1
                if t.status == TaskStatus.COMPLETED:
                    entry["completed"] += 1
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None):
        with self._lock:
            if project_id is not None and project_id not in self.projects.data:
                raise NotFoundError("project not found")
            if project_id is None:
                tasks = list(self.tasks.data.values())
            else:
                tasks = [
                    t for t in self.tasks.data.values()
                    if t.project_id == project_id
                ]
            user_ids = sorted(
                {t.assignee_id for t in tasks if t.assignee_id is not None}
            )
            stats = {uid: [0, 0] for uid in user_ids}
            for t in tasks:
                if t.assignee_id is None:
                    continue
                entry = stats[t.assignee_id]
                entry[0] += 1
                if t.status == TaskStatus.COMPLETED:
                    entry[1] += 1
            rows = []
            for uid in user_ids:
                total, completed = stats[uid]
                rows.append({
                    "user_id": uid,
                    "total_tasks": total,
                    "completed_tasks": completed,
                    "completion_rate": completed / total if total else 0.0,
                })
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        with self._lock:
            if user_id not in self.users.data:
                raise NotFoundError("user not found")
            tasks = self._assigned_tasks(user_id)
            tasks.sort(key=lambda t: t.id)
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            summary = self.get_ratings_summary(user_id)
            return {
                "report_type": ReportType.INDIVIDUAL.value,
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completed / total if total else 0.0,
                "average_completion_time":
                    self.get_average_completion_time(user_id),
                "rating_count": summary["count"],
                "rating_average": summary["average"],
                "tasks": [_clone(t) for t in tasks],
            }

    def export_report(self, report, fmt):
        if not isinstance(report, dict):
            raise ValidationError("report must be a dict")
        if not isinstance(fmt, ReportFormat):
            raise ValidationError("fmt must be a ReportFormat")
        if fmt == ReportFormat.CSV:
            return self._export_csv(report)
        return self._export_pdf(report)

    # ------------------------------------------------------------------
    # Export helpers
    # ------------------------------------------------------------------
    def _export_csv(self, report):
        output = io.StringIO()
        writer = csv.writer(output)
        rows = report.get("rows")
        if isinstance(rows, list) and rows:
            headers = list(rows[0].keys())
            writer.writerow(headers)
            for row in rows:
                writer.writerow([self._stringify(row.get(h)) for h in headers])
        else:
            writer.writerow(["field", "value"])
            for key, value in report.items():
                writer.writerow([self._stringify(key), self._stringify(value)])
        return output.getvalue()

    @staticmethod
    def _stringify(value):
        if value is None:
            return ""
        if isinstance(value, (dict, list, tuple)):
            return str(value)
        return str(value)

    def _export_pdf(self, report):
        lines = []
        report_type = report.get("report_type", "report")
        lines.append("Report: {0}".format(report_type))
        rows = report.get("rows")
        if isinstance(rows, list) and rows:
            for row in rows:
                parts = [
                    "{0}={1}".format(k, self._stringify(v))
                    for k, v in row.items()
                ]
                lines.append("; ".join(parts))
        else:
            for key, value in report.items():
                lines.append(
                    "{0}: {1}".format(key, self._stringify(value))
                )

        text_lines = []
        y = 760
        for line in lines:
            safe = self._pdf_escape(line)
            text_lines.append("BT /F1 12 Tf 50 {0} Td ({1}) Tj ET".format(y, safe))
            y -= 16
            if y < 40:
                break
        content = "\n".join(text_lines)
        content_bytes = content.encode("ascii", "replace")

        objects = []
        objects.append("<< /Type /Catalog /Pages 2 0 R >>")
        objects.append("<< /Type /Pages /Kids [3 0 R] /Count 1 >>")
        objects.append(
            "<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            "/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>"
        )
        stream = "<< /Length {0} >>\nstream\n".format(len(content_bytes))
        objects.append(stream + content + "\nendstream")
        objects.append(
            "<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>"
        )

        out = bytearray()
        out += b"%PDF-1.4\n"
        offsets = []
        for i, body in enumerate(objects, start=1):
            offsets.append(len(out))
            out += "{0} 0 obj\n".format(i).encode("ascii")
            out += body.encode("ascii", "replace")
            out += b"\nendobj\n"
        xref_pos = len(out)
        count = len(objects) + 1
        out += "xref\n0 {0}\n".format(count).encode("ascii")
        out += b"0000000000 65535 f \n"
        for off in offsets:
            out += "{0:010d} 00000 n \n".format(off).encode("ascii")
        out += (
            "trailer\n<< /Size {0} /Root 1 0 R >>\nstartxref\n{1}\n%%EOF\n"
            .format(count, xref_pos).encode("ascii")
        )
        return bytes(out)

    @staticmethod
    def _pdf_escape(text):
        return (
            text.replace("\\", "\\\\")
            .replace("(", "\\(")
            .replace(")", "\\)")
        )

    # ------------------------------------------------------------------
    # Internal helpers
    # ------------------------------------------------------------------
    def _assigned_tasks(self, user_id):
        ids = self.tasks.by_assignee.get(user_id, set())
        return [self.tasks.data[i] for i in ids if i in self.tasks.data]

    def _add_to_assignee_index(self, user_id, task_id):
        self.tasks.by_assignee.setdefault(user_id, set()).add(task_id)

    def _remove_from_assignee_index(self, user_id, task_id):
        ids = self.tasks.by_assignee.get(user_id)
        if ids is not None:
            ids.discard(task_id)
            if not ids:
                self.tasks.by_assignee.pop(user_id, None)

    @staticmethod
    def _validate_username(username):
        if username is None or not str(username).strip():
            raise ValidationError("username required")

    @staticmethod
    def _validate_email(email):
        if email is None or not str(email).strip():
            raise ValidationError("email required")
        if "@" not in email:
            raise ValidationError("invalid email")
